// test-local-plugins.mjs — functional smoke test for harness/plugins/local/*.mjs
// Run in CI on every push/PR (see .github/workflows/ci.yml, test-plugins job).
// Verifies each plugin's tool.execute.before hook actually blocks/allows the
// cases it's designed for, not just that the file parses.

import path from "node:path";
import os from "node:os";
import fs from "node:fs";
import { fileURLToPath, pathToFileURL } from "node:url";

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(SCRIPT_DIR, "..", "..");
const PLUGINS_DIR = path.join(REPO_ROOT, "harness", "plugins", "local");

let failures = 0;

function toFileUrl(p) {
  return pathToFileURL(p).href;
}

async function expectBlocked(hooks, input, output, label) {
  try {
    await hooks["tool.execute.before"](input, output);
    console.error(`FAIL (expected block): ${label}`);
    failures++;
  } catch {
    console.log(`OK (blocked): ${label}`);
  }
}

async function expectAllowed(hooks, input, output, label) {
  try {
    await hooks["tool.execute.before"](input, output);
    console.log(`OK (allowed): ${label}`);
  } catch (e) {
    console.error(`FAIL (expected allow): ${label} -> ${e.message.split("\n")[0]}`);
    failures++;
  }
}

// ── check-secrets.mjs ──────────────────────────────────────────────────────────
{
  const { CheckSecrets } = await import(toFileUrl(path.join(PLUGINS_DIR, "check-secrets.mjs")));
  const hooks = await CheckSecrets({ project: {}, client: {}, $: {}, directory: ".", worktree: "." });

  await expectBlocked(hooks, { tool: "write" }, { args: { filePath: "config.js", content: 'const key = "AKIAABCDEFGHIJKLMNOP";' } }, "AWS key in .js");
  await expectBlocked(hooks, { tool: "edit" }, { args: { filePath: "app.py", newString: 'GITHUB_TOKEN = "ghp_1234567890abcdefghijklmnopqrstuvwxyz"' } }, "GitHub token in .py");
  await expectBlocked(hooks, { tool: "write" }, { args: { filePath: "x.js", content: "-----BEGIN RSA PRIVATE KEY-----\nMIIEpAIBAAKCAQEA..." } }, "Private key block");
  await expectAllowed(hooks, { tool: "write" }, { args: { filePath: ".env", content: 'DB_PASSWORD="supersecret123"' } }, ".env password (allowed)");
  await expectAllowed(hooks, { tool: "write" }, { args: { filePath: "README.md", content: "Example JWT: eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIn0.dozjgNryP4J3jVmNHl0w5N_XgL0n3I9PlFUP0THsR8U" } }, "JWT in .md docs (allowed)");
  await expectAllowed(hooks, { tool: "read" }, { args: { filePath: "x.js" } }, "read tool is not checked (allowed)");
}

// ── check-generated-files.mjs ───────────────────────────────────────────────────
{
  const { CheckGeneratedFiles } = await import(toFileUrl(path.join(PLUGINS_DIR, "check-generated-files.mjs")));
  const hooks = await CheckGeneratedFiles({ project: {}, client: {}, $: {}, directory: ".", worktree: "." });

  const tmpGen = path.join(os.tmpdir(), "ci-test-generated.js");
  fs.writeFileSync(tmpGen, "// GENERATED FILE - DO NOT EDIT\n// @generated by tool\nconsole.log(1);");
  await expectBlocked(hooks, { tool: "edit" }, { args: { filePath: tmpGen } }, "file with GENERATED header");

  const tmpNormal = path.join(os.tmpdir(), "ci-test-normal.js");
  fs.writeFileSync(tmpNormal, "// just a normal file\nconsole.log(1);");
  await expectAllowed(hooks, { tool: "edit" }, { args: { filePath: tmpNormal } }, "normal file (allowed)");

  await expectAllowed(hooks, { tool: "edit" }, { args: { filePath: path.join(os.tmpdir(), "ci-test-does-not-exist.js") } }, "nonexistent file / new file via edit (allowed)");

  fs.unlinkSync(tmpGen);
  fs.unlinkSync(tmpNormal);
}

// ── strip-jwt.mjs ────────────────────────────────────────────────────────────────
{
  const { StripJwtPermissions } = await import(toFileUrl(path.join(PLUGINS_DIR, "strip-jwt.mjs")));
  const hooks = await StripJwtPermissions({ project: {}, client: {}, $: {}, directory: ".", worktree: "." });

  await expectBlocked(hooks, { tool: "bash" }, { args: { command: 'curl -H "Authorization: Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjM0In0" https://api.example.com' } }, "curl with raw JWT bearer");
  await expectAllowed(hooks, { tool: "bash" }, { args: { command: 'export TOKEN=$(get-token) && curl -H "Authorization: Bearer $TOKEN" https://api.example.com' } }, "JWT via variable (allowed)");
  await expectAllowed(hooks, { tool: "bash" }, { args: { command: "git status" } }, "unrelated bash command (allowed)");
}

if (failures > 0) {
  console.error(`\n${failures} test(s) failed.`);
  process.exit(1);
}
console.log("\nall local plugin smoke tests passed");
